import requests
from datetime import datetime

def import_data(zip_code, start_date):
    api_key = 'your_api_key'  # Replace with your actual API key
    base_url = f"http://api.wunderground.com/api/{api_key}/history_{start_date}/q/{zip_code}.json"

    response = requests.get(base_url)

    if response.status_code != 200:
        return {"error": "Failed to retrieve data"}

    data = response.json()

    if 'history' not in data:
        return {"error": "No history data found"}

    history_data = data['history']

    cleaned_data = {
        "date": history_data['dailysummary'][0]['date']['pretty'],
        "high_temp": history_data['dailysummary'][0]['maxtempi'],
        "low_temp": history_data['dailysummary'][0]['mintempi'],
        "precipitation": history_data['dailysummary'][0]['precipitation'],
    }

    return cleaned_data
